mapper.select:
select id
from portfolio_items
where id = #{portfolioItemId}
  and user_id = #{userId}
  and is_active = true
limit 1

mapper.insert:
insert into portfolio_item_reasons (
    portfolio_item_id,
    reason_code,
    display_order
) values (
    #{portfolioItemId},
    #{reasonCode},
    #{displayOrder}
)

mapper.select:
select id
from portfolio_weekly_reports
where user_id = #{userId}
  and report_week = #{reportWeek}
limit 1

select max(pnd.sent_at)
from push_notification_deliveries pnd
join user_alert_events uae on uae.id = pnd.alert_event_id
where pnd.user_id = #{userId}
  and uae.portfolio_item_id = #{portfolioItemId}
  and pnd.alert_type = #{alertType}
  and pnd.delivery_status = 'SENT'

mapper.update:
update user_alert_events
set read_at = now()
where user_id = #{userId}
  and id = #{alertId}
  and read_at is null

update push_notification_deliveries
set delivery_status = 'SENT',
    provider_message_id = #{providerMessageId},
    sent_at = #{sentAt},
    delivered_at = #{sentAt}
where dedupe_key = #{dedupeKey}

update push_notification_deliveries
set delivery_status = 'FAILED',
    provider_error_code = #{providerErrorCode},
    provider_error_message = #{providerErrorMessage},
    sent_at = #{sentAt}
where dedupe_key = #{dedupeKey}

update weekly_notification_jobs
set job_status = #{jobStatus},
    target_device_count = #{targetDeviceCount},
    success_count = #{successCount},
    failure_count = #{failureCount},
    started_at = #{startedAt},
    completed_at = #{completedAt},
    error_message = #{errorMessage}
where user_id = #{userId}
  and report_week = #{reportWeek}
